from typing import Dict, List, Tuple, Optional
from enum import Enum
from dataclasses import dataclass
from collections import deque

class BoundaryType(Enum):
    ROUGH = 'rough'
    SMOOTH = 'smooth'

@dataclass
class Patch:
    id: str
    position: Tuple[int, int]
    distance: int
    boundaries: Tuple[BoundaryType, BoundaryType, BoundaryType, BoundaryType]

class PatchManager:
    def __init__(self, grid_size: Tuple[int, int]):
        self.rows, self.cols = grid_size
        self.patches: Dict[str, Patch] = {}
        self.positions: Dict[Tuple[int, int], str] = {}

    def add_patch(self, patch: Patch) -> bool:
        r, c = patch.position
        if not (0 <= r < self.rows and 0 <= c < self.cols):
            return False
        if patch.position in self.positions:
            return False
        if patch.id in self.patches:
            return False

        self.patches[patch.id] = patch
        self.positions[patch.position] = patch.id
        return True

    def get_adjacent(self, patch_id: str) -> Dict[str, Optional[str]]:
        if patch_id not in self.patches:
            return {'top': None, 'right': None, 'bottom': None, 'left': None}

        patch = self.patches[patch_id]
        r, c = patch.position

        result = {
            'top': self.positions.get((r - 1, c)),
            'right': self.positions.get((r, c + 1)),
            'bottom': self.positions.get((r + 1, c)),
            'left': self.positions.get((r, c - 1))
        }
        return result

    def can_merge(self, patch1_id: str, patch2_id: str) -> Tuple[bool, str]:
        if patch1_id not in self.patches or patch2_id not in self.patches:
            return False, 'Patch not found'

        p1 = self.patches[patch1_id]
        p2 = self.patches[patch2_id]

        # Find which direction they're adjacent
        adjacent = self.get_adjacent(patch1_id)
        direction = None
        for d, adj_id in adjacent.items():
            if adj_id == patch2_id:
                direction = d
                break

        if direction is None:
            return False, 'Patches not adjacent'

        # Get boundary types
        dir_to_idx = {'top': 0, 'right': 1, 'bottom': 2, 'left': 3}
        opposite = {'top': 'bottom', 'right': 'left', 'bottom': 'top', 'left': 'right'}

        b1 = p1.boundaries[dir_to_idx[direction]]
        b2 = p2.boundaries[dir_to_idx[opposite[direction]]]

        if b1 != b2:
            return False, f'Incompatible boundaries: {b1.value} vs {b2.value}'

        measurement = 'XX' if b1 == BoundaryType.ROUGH else 'ZZ'
        return True, measurement

    def find_path(self, start_id: str, end_id: str) -> List[str]:
        if start_id not in self.patches or end_id not in self.patches:
            return []

        if start_id == end_id:
            return [start_id]

        # BFS
        queue = deque([(start_id, [start_id])])
        visited = {start_id}

        while queue:
            current, path = queue.popleft()

            for direction, adj_id in self.get_adjacent(current).items():
                if adj_id is None or adj_id in visited:
                    continue

                new_path = path + [adj_id]

                if adj_id == end_id:
                    return new_path

                visited.add(adj_id)
                queue.append((adj_id, new_path))

        return []

from typing import List, Dict, Tuple, Set, Optional
import heapq

class SurgeryRouter:
    def __init__(self, rows: int, cols: int, distance: int):
        self.rows = rows
        self.cols = cols
        self.d = distance
        self.occupied: Set[Tuple[int, int]] = set()
        self.patch_positions: Dict[str, Tuple[int, int]] = {}

    def place_patch(self, patch_id: str, position: Tuple[int, int]) -> bool:
        r, c = position
        if not (0 <= r < self.rows and 0 <= c < self.cols):
            return False
        if position in self.occupied:
            return False

        self.occupied.add(position)
        self.patch_positions[patch_id] = position
        return True

    def _heuristic(self, a: Tuple[int, int], b: Tuple[int, int]) -> int:
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    def a_star_path(self, start: Tuple[int, int],
                    end: Tuple[int, int]) -> List[Tuple[int, int]]:
        if start == end:
            return [start]

        # Priority queue: (f_score, g_score, position, path)
        heap = [(self._heuristic(start, end), 0, start, [start])]
        visited = set()

        while heap:
            f, g, current, path = heapq.heappop(heap)

            if current == end:
                return path

            if current in visited:
                continue
            visited.add(current)

            r, c = current
            for dr, dc in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
                nr, nc = r + dr, c + dc
                next_pos = (nr, nc)

                if not (0 <= nr < self.rows and 0 <= nc < self.cols):
                    continue
                if next_pos in visited:
                    continue
                if next_pos in self.occupied and next_pos != end:
                    continue

                new_g = g + 1
                new_f = new_g + self._heuristic(next_pos, end)
                new_path = path + [next_pos]
                heapq.heappush(heap, (new_f, new_g, next_pos, new_path))

        return []  # No path

    def route_operation(self, patch1_id: str,
                        patch2_id: str) -> Dict:
        if patch1_id not in self.patch_positions:
            return {'error': f'Patch {patch1_id} not found'}
        if patch2_id not in self.patch_positions:
            return {'error': f'Patch {patch2_id} not found'}

        pos1 = self.patch_positions[patch1_id]
        pos2 = self.patch_positions[patch2_id]

        # Check if adjacent
        if self._heuristic(pos1, pos2) == 1:
            return {
                'strategy': 'direct',
                'path': [pos1, pos2],
                'ancilla_count': 0,
                'time_overhead': 0
            }

        # Find path
        path = self.a_star_path(pos1, pos2)

        if not path:
            return {
                'strategy': 'failed',
                'error': 'No path available'
            }

        # Path length - 2 = number of intermediate positions
        ancilla_count = len(path) - 2
        time_overhead = ancilla_count * self.d  # Each ancilla adds d cycles

        return {
            'strategy': 'routed',
            'path': path,
            'ancilla_count': ancilla_count,
            'time_overhead': time_overhead,
            'total_time': 6 * self.d + time_overhead
        }

    def optimize_multi_operation(self,
                                  operations: List[Tuple[str, str]]) -> Dict:
        results = []
        total_overhead = 0

        for p1, p2 in operations:
            route = self.route_operation(p1, p2)
            results.append({
                'operation': f'{p1} <-> {p2}',
                'route': route
            })
            if 'time_overhead' in route:
                total_overhead += route['time_overhead']

        # Check for parallel opportunities
        parallel_groups = self._find_parallel_groups(operations)

        return {
            'operations': len(operations),
            'total_routing_overhead': total_overhead,
            'results': results,
            'parallel_groups': parallel_groups
        }

    def _find_parallel_groups(self, 
                               operations: List[Tuple[str, str]]) -> List[List[int]]:
        # Find operations that don't share qubits
        groups = []
        used = set()
        current_group = []

        for i, (p1, p2) in enumerate(operations):
            if p1 not in used and p2 not in used:
                current_group.append(i)
                used.add(p1)
                used.add(p2)

        if current_group:
            groups.append(current_group)

        return groups
